            //
            aOrbiterI = (aOrbiterI + aOrbiterF) + 6879775463419106139U;
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 1373114894940964375U;
            aOrbiterC = RotL64((aOrbiterC * 9792942628856528045U), 39U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 4502496434522644603U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterE) ^ 2350923198279175348U) ^ aNonceWordA;
            aOrbiterF = RotL64((aOrbiterF * 836303913329451945U), 21U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterK) + 9656308475143286251U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterF) ^ 7193262464324245478U) ^ aNonceWordK;
            aOrbiterJ = RotL64((aOrbiterJ * 1519984292004086253U), 47U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 12237199152698288586U;
