            aOrbiterG = (aOrbiterG + aOrbiterA) + 11687632895352815190U;
            aOrbiterB = (aOrbiterB ^ aOrbiterG) ^ 9153068947659624506U;
            aOrbiterB = RotL64((aOrbiterB * 8550453782677688605U), 23U);
            //
            aOrbiterC = (((aOrbiterC + aOrbiterJ) + 16010259476432619698U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 29U)) & S_SALT1]) + aNonceWordO;
