            //
            aOrbiterG = (aOrbiterG + aOrbiterK) + 2619504572127223536U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterG) ^ 14929647779840084906U) ^ aOrbiterUpdateSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 852448695490810407U), 5U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 7297168888526209867U;
            aOrbiterA = (aOrbiterA ^ aOrbiterB) ^ 12991146192092675126U;
            aOrbiterA = RotL64((aOrbiterA * 14841310331496067245U), 29U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterH) + 10957450116094578552U;
            aOrbiterG = ((aOrbiterG ^ aOrbiterD) ^ 17617201755900378723U) ^ aOrbiterUpdateSaltA[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 14561407564731250661U), 53U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterG) + 4943431736862701308U) + aOrbiterUpdateSaltE[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 11682431941290124729U;
