            //
            aOrbiterC = ((aOrbiterC + aOrbiterA) + 16266633983912149904U) + aOrbiterUpdateSaltC[((aIndex + 23U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 14249291775528013462U;
